import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import FileUploader from '../../components/Admin/FileUploader';

const BASE_URL = 'http://localhost:5000';

const HeroManager = () => {
  const navigate = useNavigate();
  const [title, setTitle] = useState('');
  const [subtitle, setSubtitle] = useState('');
  const [buttonText, setButtonText] = useState('');
  const [buttonLink, setButtonLink] = useState('');
  const [mediaType, setMediaType] = useState('video');
  const [currentMediaUrl, setCurrentMediaUrl] = useState('');
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const fetchHero = async () => {
      try {
        const { data } = await api.get('/hero');
        setTitle(data.title || '');
        setSubtitle(data.subtitle || '');
        setButtonText(data.buttonText || '');
        setButtonLink(data.buttonLink || '');
        setMediaType(data.mediaType || 'video');
        setCurrentMediaUrl(data.mediaUrl || '');
      } catch (error) {
        console.error('Error fetching hero:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchHero();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);

    const formData = new FormData();
    formData.append('title', title);
    formData.append('subtitle', subtitle);
    formData.append('buttonText', buttonText);
    formData.append('buttonLink', buttonLink);
    formData.append('mediaType', mediaType);
    if (file) {
      formData.append('media', file);
    }

    try {
      await api.put('/hero', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      alert('Hero section updated successfully!');
    } catch (error) {
      console.error('Error updating hero:', error);
      alert('Error updating hero section');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div>Loading hero settings...</div>;

  return (
    <div className="max-w-3xl">
      <h1 className="text-3xl font-serif font-bold mb-8">Hero Section</h1>

      <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg border border-border shadow-sm space-y-6">
        <div>
          <label className="block text-sm font-medium mb-2">Title</label>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
            placeholder="Redefining Luxury"
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Subtitle</label>
          <input
            type="text"
            value={subtitle}
            onChange={(e) => setSubtitle(e.target.value)}
            className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
            placeholder="Discover the essentials of modern minimalism."
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-2">Button Text</label>
            <input
              type="text"
              value={buttonText}
              onChange={(e) => setButtonText(e.target.value)}
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
              placeholder="Explore Collection"
            />
          </div>
          <div>
            <label className="block text-sm font-medium mb-2">Button Link</label>
            <input
              type="text"
              value={buttonLink}
              onChange={(e) => setButtonLink(e.target.value)}
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
              placeholder="/shop"
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Media Type</label>
          <div className="flex gap-4">
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="mediaType"
                value="video"
                checked={mediaType === 'video'}
                onChange={(e) => setMediaType(e.target.value)}
                className="accent-black"
              />
              <span className="text-sm">Video</span>
            </label>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="mediaType"
                value="image"
                checked={mediaType === 'image'}
                onChange={(e) => setMediaType(e.target.value)}
                className="accent-black"
              />
              <span className="text-sm">Image</span>
            </label>
          </div>
        </div>

        {currentMediaUrl && (
          <div>
            <label className="block text-sm font-medium mb-2">Current Media</label>
            <div className="border border-border rounded-lg overflow-hidden inline-block">
              {mediaType === 'video' ? (
                <video src={`${BASE_URL}${currentMediaUrl}`} controls className="max-h-48 object-contain bg-black" />
              ) : (
                <img src={`${BASE_URL}${currentMediaUrl}`} alt="Current hero" className="max-h-48 object-contain bg-gray-light" />
              )}
            </div>
          </div>
        )}

        <div>
          <label className="block text-sm font-medium mb-2">Upload New Media</label>
          <FileUploader
            onFileSelect={(f) => setFile(f)}
            accept={mediaType === 'video' ? 'video/*' : 'image/*'}
          />
        </div>

        <div className="flex gap-4 pt-4 border-t border-border">
          <button
            type="submit"
            disabled={saving}
            className="bg-black text-white px-6 py-2 rounded hover:bg-gray-dark transition-colors disabled:opacity-50"
          >
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
          <button
            type="button"
            onClick={() => navigate('/admin')}
            className="bg-white text-black border border-border px-6 py-2 rounded hover:bg-gray-light transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
};

export default HeroManager;
